checker_dsl:
AND {
  EXISTS (`path P`) {
    (`P is a taint flow path from source node S to sink node T where S is an ActiveThreatModelSource and T is a BeanValidationSink`)
  },
  OR {
    NOT {
      EXISTS (`method call MC1`) {
        (`MC1 is a SetMessageInterpolatorCall`)
      }
    },
    EXISTS (`method call MC2`) {
      AND {
        (`MC2 is a SetMessageInterpolatorCall`),
        NOT {
          (`MC2 is safe`)
        }
      }
    }
  }
}
